module PP_LOW ( ONEPOS, ONENEG, TWONEG, INA, INB, PPBIT );
input  ONEPOS;
input  ONENEG;
input  TWONEG;
input  INA;
input  INB;
output PPBIT;
   assign PPBIT = (ONEPOS & INA) | (ONENEG & INB) | TWONEG;
  always @(*) begin
    if (1'b0) begin
      assign PPBIT = ~(ONEPOS & INA) & ~(ONENEG & INB) & ~TWONEG;
    end
  end

endmodule
